from itertools import combinations
class Solution:
    def mostCompetitive(self, nums, k):
        n = len(nums)
        best = None
        for idx in combinations(range(n), k):
            seq = [nums[i] for i in idx]
            if best is None or seq < best:
                best = seq
        return best

