class Solution:
    def mostCompetitive(self, nums, k):
        stack = []
        n = len(nums)
        for i, x in enumerate(nums):
            while stack and stack[-1] > x and len(stack) - 1 + (n - i) >= k:
                stack.pop()
            if len(stack) < k:
                stack.append(x)
        return stack

