var mostCompetitive = function(nums, k) {
    const stack = [];
    const n = nums.length;
    for (let i = 0; i < n; i++) {
        const x = nums[i];
        while (stack.length && stack[stack.length - 1] > x && stack.length - 1 + (n - i) >= k) {
            stack.pop();
        }
        if (stack.length < k) stack.push(x);
    }
    return stack;
};
